let prompt = $json["body"] || $json["data"] || '';
if (!prompt.toLowerCase().includes("nativewind")) {
  prompt += "\n\nAsigură-te că folosești NativeWind pentru stilizare (config corect în babel.config.js și tailwind.config.js).";
}
return [{ json: { prompt_clean: prompt } }];

// Parse Claude's response
const response = $json;
let content = '';

// Extract content from Claude's response structure
if (response.content && Array.isArray(response.content)) {
  content = response.content
    .filter(item => item.type === 'text')
    .map(item => item.text)
    .join('\n');
} else if (response.body && response.body.content) {
  content = response.body.content[0].text;
} else if (typeof response === 'string') {
  content = response;
}

// Extract code blocks and file structures
const codeBlocks = [];
const fileRegex = /```(?:jsx?|tsx?|json|js|ts)\n([\s\S]*?)```/g;
const fileNameRegex = /\/\/ File: (.+?)\n|\# File: (.+?)\n|\/\* File: (.+?) \*\//;

let match;
while ((match = fileRegex.exec(content)) !== null) {
  const code = match[1];
  const fileNameMatch = code.match(fileNameRegex);
  const fileName = fileNameMatch ? (fileNameMatch[1] || fileNameMatch[2] || fileNameMatch[3]).trim() : 'unknown.js';

  codeBlocks.push({
    fileName,
    content: code.replace(fileNameRegex, '').trim()
  });
}

// If no code blocks found, try to parse the entire content
if (codeBlocks.length === 0 && content.includes('import React')) {
  codeBlocks.push({
    fileName: 'App.js',
    content: content
  });
}

return [{ 
  json: { 
    parsedCode: codeBlocks,
    rawResponse: content,
    timestamp: new Date().toISOString()
  } 
}];

// Generate React Native project structure
