// Add generated code files
parsedCode.forEach(file => {
  projectStructure[file.fileName] = file.content;
});

// If no App.js was generated, add a default one
if (!projectStructure['App.js'] && !projectStructure['App.tsx']) {
  projectStructure['App.js'] = `import React from 'react';
import { View, Text, StyleSheet, SafeAreaView } from 'react-native';

export default function App() {
  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.content}>
        <Text style={styles.title}>React Native App</Text>
        <Text style={styles.subtitle}>Generated with n8n + Claude</Text>
