}

// Convert to files array
for (const [path, content] of Object.entries(projectStructure)) {
  files.push({
    path,
    content: typeof content === 'object' ? JSON.stringify(content, null, 2) : content
  });
}

return [{ 
  json: { 
    projectName,
    files,
    totalFiles: files.length,
    timestamp: new Date().toISOString()
  } 
}];

// Create a downloadable archive or return structure
const { projectName, files } = $json;
const timestamp = new Date().toISOString().replace(/[:.]/g, '-');

// Create response with file structure and download links
const response = {
  success: true,
  projectName,
  timestamp,
  message: `Proiect React Native generat cu succes! ${files.length} fișiere create.`,
  structure: files.map(f => ({
    path: f.path,
